import NextAuth from "next-auth";
import GoogleProvider from "next-auth/providers/google";

export const authOptions = {
  providers: [
    GoogleProvider({
      clientId: process.env.GOOGLE_CLIENT_ID || "",
      clientSecret: process.env.GOOGLE_CLIENT_SECRET || "", // User didn't provide secret, prompt them or assuming they have it in env
    }),
  ],
  pages: {
    signIn: "/auth/signin",
  },
  callbacks: {
    async session({ session, token }: any) {
      session.user.id = token.sub;
      return session;
    },
  },
};

const handler = NextAuth(authOptions);

export { handler as GET, handler as POST };

"use client";

import { useSession, signIn, signOut } from "next-auth/react";
import Image from "next/image";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Loader2, LogOut, Film, Trash2 } from "lucide-react";

export default function Dashboard() {
  const { data: session, status } = useSession();

  if (status === "loading") {
    return (
        <div className="min-h-screen bg-black flex items-center justify-center">
            <Loader2 className="w-8 h-8 text-pink-500 animate-spin" />
        </div>
    );
  }

  if (status === "unauthenticated") {
    // Redirect or show login
    return (
        <div className="min-h-screen bg-black text-white flex flex-col items-center justify-center gap-6">
            <Image src="/assets/logo.png" alt="Logo" width={64} height={64} className="opacity-80" />
            <h1 className="text-2xl font-bold">Sign In to Dashboard</h1>
            <Button onClick={() => signIn("google")} className="bg-white text-black hover:bg-zinc-200">
                Continue with Google
            </Button>
        </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white p-8">
      <nav className="max-w-6xl mx-auto flex items-center justify-between mb-12">
        <div className="flex items-center gap-2">
            <Image src="/assets/logo.png" alt="Logo" width={32} height={32} />
            <h1 className="font-bold">QuickAI Dashboard</h1>
        </div>
        <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
                {session?.user?.image && (
                    <Image 
                        src={session.user.image} 
                        alt="User" 
                        width={32} 
                        height={32} 
                        className="rounded-full border border-zinc-800"
                    />
                )}
                <span className="text-sm font-medium">{session?.user?.name}</span>
            </div>
            <Button variant="ghost" size="icon" onClick={() => signOut()}>
                <LogOut className="w-4 h-4 text-zinc-400" />
            </Button>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <Card className="bg-zinc-900 border-zinc-800">
                <CardHeader>
                    <CardTitle className="text-2xl font-bold">0</CardTitle>
                    <CardDescription>Shorts Created</CardDescription>
                </CardHeader>
            </Card>
            <Card className="bg-zinc-900 border-zinc-800">
                <CardHeader>
                    <CardTitle className="text-2xl font-bold">0 hrs</CardTitle>
                    <CardDescription>Processing Saved</CardDescription>
                </CardHeader>
            </Card>
            <Card className="bg-zinc-900 border-zinc-800">
                <CardHeader>
                    <CardTitle className="text-2xl font-bold text-green-400">$0.00</CardTitle>
                    <CardDescription>Server Costs</CardDescription>
                </CardHeader>
            </Card>
        </div>

        <div>
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                <Film className="w-5 h-5 text-pink-500" />
                History
            </h2>
            <Card className="bg-zinc-950 border-zinc-900 min-h-[300px] flex items-center justify-center">
                <CardContent className="text-zinc-500 text-center">
                    <p>No history found.</p>
                    <p className="text-xs mt-1">Your local exports are not tracked unless you enable sync.</p>
                </CardContent>
            </Card>
        </div>
      </main>
    </div>
  );
}

"use client";

import { useEffect, useState, useRef } from "react";
import { useSearchParams } from "next/navigation";
import { FFmpeg } from "@ffmpeg/ffmpeg";
import { fetchFile, toBlobURL } from "@ffmpeg/util";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Progress } from "@/components/ui/progress";
import { Loader2, Scissors, AlertCircle, Wand2 } from "lucide-react";
import Image from "next/image";

// Dynamic import for Whisper
import { pipeline } from "@xenova/transformers"; 

export default function EditorPage() {
  const searchParams = useSearchParams();
  const videoId = searchParams.get("v");
  
  const [loaded, setLoaded] = useState(false);
  const [whisperLoaded, setWhisperLoaded] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [message, setMessage] = useState("Initializing Browser Engine...");
  const [progress, setProgress] = useState(0);
  const [videoInfo, setVideoInfo] = useState<any>(null);
  const [error, setError] = useState("");
  
  const ffmpegRef = useRef(new FFmpeg());
  const messageRef = useRef<HTMLParagraphElement | null>(null);

  const load = async () => {
    setIsLoading(true);
    const baseURL = "https://unpkg.com/@ffmpeg/core@0.12.6/dist/esm";
    const ffmpeg = ffmpegRef.current;
    
    ffmpeg.on("log", ({ message }) => {
      if (messageRef.current) messageRef.current.innerHTML = message;
    });

    ffmpeg.on("progress", ({ progress }) => {
      setProgress(Math.round(progress * 100));
    });

    try {
      await ffmpeg.load({
        coreURL: await toBlobURL(`${baseURL}/ffmpeg-core.js`, "text/javascript"),
        wasmURL: await toBlobURL(`${baseURL}/ffmpeg-core.wasm`, "application/wasm"),
      });
      setLoaded(true);
      setMessage("FFmpeg Engine Ready");
      
      // Load Whisper
      try {
        await pipeline('automatic-speech-recognition', 'Xenova/whisper-tiny.en');
        setWhisperLoaded(true); 
        setMessage("AI Engines Ready");
      } catch (whisperError) {
        console.warn("Soft Error: Whisper failed to load. Transcription will be disabled.", whisperError);
        setMessage("FFmpeg Ready (Whisper Offline)");
      }

      if (videoId) {
        fetchVideoInfo(videoId);
      }
    } catch (error) {
      console.error(error);
      setError("Failed to load engine. Please use Chrome/Edge on Desktop.");
      setMessage("Engine Load Failed");
    } finally {
      setIsLoading(false);
    }
  };

  const fetchVideoInfo = async (id: string) => {
    setMessage("Fetching video meta...");
    try {
        const res = await fetch(`http://localhost:8000/api/info?url=https://www.youtube.com/watch?v=${id}`);
        if (!res.ok) throw new Error("Failed to fetch video info");
        const data = await res.json();
        setVideoInfo(data);
        setMessage("Ready to Process");
    } catch (e) {
        console.error(e);
        setError("Could not retrieve video information. Ensure backend is running.");
    }
  };

  const processVideo = async () => {
    if (!videoInfo || !ffmpegRef.current.loaded) return;
    const ffmpeg = ffmpegRef.current;
    
    try {
        setMessage("Downloading & Transcoding (This happens locally)...");
        // Use the proxy to get the video file
        const videoURL = `http://localhost:8000/api/proxy?url=https://www.youtube.com/watch?v=${videoId}`;
        
        // Write the file to memory
        await ffmpeg.writeFile("input.mp4", await fetchFile(videoURL));
        
        setMessage("Analyzing Audio Peaks...");
        // Placeholder for peak detection logic using web audio api or ffmpeg silence detect
        // await ffmpeg.exec(['-i', 'input.mp4', '-af', 'silencedetect=noise=-30dB:d=0.5', '-f', 'null', '-']);

        setMessage("Cutting Highlight (00:00 - 00:10)...");
        // Simple cut command for demonstration
        await ffmpeg.exec([
            '-i', 'input.mp4',
            '-ss', '00:00:00',
            '-t', '00:00:10',
            '-vf', 'scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2',
            '-c:v', 'libx264',
            '-preset', 'ultrafast',
            'output.mp4'
        ]);

        setMessage("Exporting...");
        const data = await ffmpeg.readFile("output.mp4");
        
        // Create download link
        const url = URL.createObjectURL(new Blob([data as any], { type: "video/mp4" }));
        const a = document.createElement("a");
        a.href = url;
        a.download = `quickai_short_${videoId}.mp4`;
        a.click();
        
        setMessage("Done!");
    } catch (e) {
        console.error(e);
        setError("Processing failed. Check console for FFmpeg logs.");
    }
  };

  useEffect(() => {
    load();
  }, []);

  return (
    <div className="min-h-screen bg-black text-white p-8 font-sans">
      <nav className="flex items-center justify-between mb-8 border-b border-zinc-900 pb-4">
        <div className="flex items-center gap-2">
          <Image src="/assets/logo.png" alt="Logo" width={32} height={32} className="w-8 h-8 object-contain" />
          <h1 className="text-lg font-bold tracking-tight">QuickAI Shorts</h1>
        </div>
        <div className="flex items-center gap-4 text-xs font-mono">
           <div className="flex items-center gap-2">
               <div className={`w-2 h-2 rounded-full ${loaded ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-amber-500 animate-pulse'}`} />
               <span className="text-zinc-400">{loaded ? "FFmpeg: Active" : "FFmpeg: Loading..."}</span>
           </div>
           <div className="flex items-center gap-2">
               <div className={`w-2 h-2 rounded-full ${whisperLoaded ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-red-500/50'}`} />
               <span className="text-zinc-400">{whisperLoaded ? "Whisper: Active" : "Whisper: Offline"}</span>
           </div>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8">
        
        {/* Left Column: Preview & Status */}
        <div className="lg:col-span-2 space-y-6">
            <div className="aspect-video bg-zinc-900 rounded-xl overflow-hidden border border-zinc-800 shadow-2xl relative group">
                {videoId ? (
                     <iframe 
                     width="100%" 
                     height="100%" 
                     src={`https://www.youtube.com/embed/${videoId}?enablejsapi=1`} 
                     title="YouTube video player" 
                     frameBorder="0" 
                     allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                     allowFullScreen
                     className="w-full h-full"
                 ></iframe>
                ) : (
                    <div className="flex items-center justify-center h-full text-zinc-500 pb-10">
                        No Video Loaded
                    </div>
                )}
                
                {isLoading && (
                    <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center gap-4 backdrop-blur-sm z-10 transition-all">
                        <Loader2 className="w-10 h-10 text-pink-500 animate-spin" />
                        <p className="text-sm font-medium text-zinc-300">{message}</p>
                        <Progress value={progress} className="w-1/2 h-1 bg-zinc-800" />
                    </div>
                )}
            </div>

            <Card className="bg-zinc-950 border-zinc-900">
                <CardHeader className="pb-2">
                    <CardTitle className="text-sm font-medium text-zinc-400">System Logs</CardTitle>
                </CardHeader>
                <CardContent>
                    <div className="h-32 overflow-y-auto font-mono text-xs text-green-500/80 p-2 bg-black/50 rounded border border-zinc-900" ref={messageRef}>
                        {message}
                    </div>
                </CardContent>
            </Card>
        </div>

        {/* Right Column: Controls */}
        <div className="space-y-6">
            {videoInfo && (
                <div className="animate-in fade-in slide-in-from-right duration-500">
                    <h2 className="text-lg font-bold mb-1 line-clamp-2">{videoInfo.title}</h2>
                    <p className="text-zinc-500 text-xs mb-4">{videoInfo.id}</p>
                </div>
            )}

            <Card className="bg-zinc-900 border-zinc-800">
               <CardContent className="p-4 space-y-4">
                    <Button 
                        className="w-full h-12 bg-linear-to-r from-pink-600 to-violet-600 hover:from-pink-500 hover:to-violet-500 text-white font-semibold rounded-lg shadow-lg shadow-pink-900/20 transition-all active:scale-[0.98]"
                        onClick={processVideo}
                        disabled={!loaded || isLoading}
                    >
                        {isLoading ? <Loader2 className="mr-2 animate-spin" /> : <Wand2 className="mr-2 w-4 h-4" />}
                        Generate Magic Short
                    </Button>
                    
                    <div className="grid grid-cols-2 gap-2">
                         <Button variant="outline" className="border-zinc-800 bg-zinc-900/50 hover:bg-zinc-800 text-zinc-400">
                            <Scissors className="mr-2 w-3 h-3" /> Manual
                        </Button>
                        <Button variant="outline" className="border-zinc-800 bg-zinc-900/50 hover:bg-zinc-800 text-zinc-400" disabled={!whisperLoaded}>
                             Transcribe
                        </Button>
                    </div>

                    {error && (
                        <div className="p-3 bg-red-950/30 border border-red-900/50 rounded-lg flex items-start gap-2 text-xs text-red-400">
                            <AlertCircle className="w-4 h-4 shrink-0 mt-0.5" />
                            {error}
                        </div>
                    )}
               </CardContent>
            </Card>

             <div className="p-4 rounded-xl border border-dashed border-zinc-800 text-center">
                <p className="text-zinc-500 text-sm mb-2">Pro Parameters</p>
                <div className="grid grid-cols-2 gap-2 text-xs text-zinc-400">
                    <div className="bg-zinc-900 p-2 rounded">9:16 Ratio</div>
                    <div className="bg-zinc-900 p-2 rounded">Smart Cut</div>
                    <div className="bg-zinc-900 p-2 rounded">Captions</div>
                    <div className="bg-zinc-900 p-2 rounded">Watermarked</div>
                </div>
            </div>
        </div>

      </main>
    </div>
  );
}

"use client";

import { useEffect } from "react";
import { Button } from "@/components/ui/button";

export default function Error({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  useEffect(() => {
    console.error(error);
  }, [error]);

  return (
    <div className="min-h-screen bg-black text-white flex flex-col items-center justify-center space-y-4">
      <h2 className="text-2xl font-bold text-red-500">Something went wrong!</h2>
      <p className="text-zinc-400 max-w-md text-center">
        Don't worry, this error has been captured. Try refreshing or going back home.
      </p>
      <div className="flex gap-4">
          <Button onClick={() => reset()} variant="secondary">
            Try again
          </Button>
          <Button onClick={() => window.location.href = '/'} variant="outline" className="border-zinc-800 text-zinc-300">
            Go Home
          </Button>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Image from "next/image";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input"; // Need to add Input component
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
} from "@/components/ui/card";
import { ArrowRight, Youtube } from "lucide-react";

export default function Home() {
  const [url, setUrl] = useState("");
  const router = useRouter();

  const handleStart = () => {
    let videoId = "";
    try {
      const u = new URL(url);
      if (u.hostname.includes("youtube.com")) {
        videoId = u.searchParams.get("v") || "";
      } else if (u.hostname.includes("youtu.be")) {
        videoId = u.pathname.slice(1);
      }
    } catch (e) {
      // invalid url
    }

    if (videoId) {
      router.push(`/editor?v=${videoId}`);
    }
  };

  return (
    <div className="min-h-screen bg-black text-white overflow-hidden relative selection:bg-pink-500/30">
      {/* Background Gradients */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[1000px] h-[600px] bg-pink-600/20 blur-[120px] rounded-full pointer-events-none" />
      <div className="absolute bottom-0 right-0 w-[800px] h-[600px] bg-violet-600/10 blur-[120px] rounded-full pointer-events-none" />

      <div className="relative z-10 max-w-6xl mx-auto px-6 py-12 flex flex-col items-center justify-center min-h-[80vh] text-center space-y-8">
        <div className="flex items-center gap-2 mb-8 animate-fade-in">
          <Image
            src="/assets/logo.png"
            alt="Logo"
            width={64}
            height={64}
            className="w-16 h-16 object-contain drop-shadow-[0_0_15px_rgba(236,72,153,0.5)]"
          />
        </div>

        <h1 className="text-5xl md:text-7xl font-bold tracking-tighter bg-clip-text text-transparent bg-linear-to-b from-white to-zinc-500 max-w-4xl mx-auto">
          Create Viral Shorts <br />
          <span className="text-transparent bg-clip-text bg-linear-to-r from-pink-500 via-rose-500 to-violet-500">
            Forever Free.
          </span>
        </h1>

        <p className="text-xl text-zinc-400 max-w-2xl mx-auto">
          Zero-cost, client-side AI processing. No servers, no waiting.
          Transform long YouTube videos into engaging shorts instantly.
        </p>

        <div className="w-full max-w-md mx-auto space-y-4">
          <div className="flex gap-2 p-1 bg-zinc-900/50 backdrop-blur-xl border border-zinc-800 rounded-full pl-6 pr-2 py-2 shadow-2xl">
            <Input
              placeholder="Paste YouTube Link..."
              className="bg-transparent border-none text-white focus-visible:ring-0 placeholder:text-zinc-600 h-10 text-lg"
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleStart()}
              suppressHydrationWarning
            />
            <Button
              size="lg"
              className="rounded-full bg-white text-black hover:bg-zinc-200 px-8"
              onClick={handleStart}
              suppressHydrationWarning
            >
              Start <ArrowRight className="ml-2 w-4 h-4" />
            </Button>
          </div>
          <p className="text-xs text-zinc-600">
            100% Local Processing ??? Hardware Accelerated ??? No Watermark (Pro)
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mt-20 w-full text-left">
          {[
            {
              title: "Client-Side Processing",
              desc: "Your GPU does the heavy lifting via WebCodecs & FFmpeg.wasm.",
            },
            {
              title: "AI Transcription",
              desc: "On-device Whisper model for accurate, privacy-focused captions.",
            },
            {
              title: "Smart Clipping",
              desc: "Heuristic algorithms detect peak moments automatically.",
            },
          ].map((i, k) => (
            <div
              key={k}
              className="p-6 rounded-2xl bg-zinc-900/40 border border-zinc-800/50 backdrop-blur-sm"
            >
              <h3 className="font-semibold text-lg mb-2 text-zinc-200">
                {i.title}
              </h3>
              <p className="text-zinc-400 text-sm">{i.desc}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
